INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00433', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「我們對於一件東西的了解，可分兩種方式，理性的方式要靠觀察、調查和資料，但是所得的結果往 往是知識多於了解，現象多於真相。直覺的方式則有賴想像，有賴詩人設身處地，想像他自己是別的 人物，這樣投入萬事萬物的結果，會依次產生了解、同情、共鳴，而終於合一。我們通常所謂的同情， 其實就是部分的或短暫的合一。我們同情雪中折翼的麻雀，是因為一剎那間，我們想像自己也是受難 的小鳥。」 依據上文，作者所要表達的意思是：', '["直覺的方式比理性有效", "知識無助了解事情真相", "詩人的可貴在引發共鳴", "同情係藉想像物我合一 直覺和理性是一體兩面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00434', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「芬蘭教育的核心價值是平等，強調的是一種不競爭教育。芬蘭人認為每個孩子的起點、學習能力不 同，在不一樣的基礎上排名、競爭是不公平的，也沒有意義，而且分數不能代表學生的全部。芬蘭教 育的目標是要給孩子一個美好的人生。他們認為讓學生花較多的時間演練解題，可能提高數理成績， 但很難提升閱讀、寫作及思考能力，而且還可能會抑制學生創新思維的發展。」 根據上文，下列敘述正確的是：', '["芬蘭強調不競爭教育，因為最好的教育是無所作為", "芬蘭反對讓學生不斷演練解題，顯示他們根本不看重數理", "芬蘭認為花較多的時間演練數理解題，有可能會抑制學生創新思維的發展", "芬蘭認為演練解題和閱讀思考之間，只能擇一，因為兩者會產生嚴重互相排擠效應 芬蘭認為排名、競爭不公平、沒有意義的原因，是因為每個學生起點、學習能力不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00435', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「美濃最美者，一、山如屏風，永在眼簾，不遠不近；二、田如平鏡，永在腳邊，綠蔥蔥的、水汪汪 的，一大片佈撒開來。遠山與平田，是美濃最完美的組合；山不甚高，亦不甚矮。山的前面，躺著平 平的綠田，因為有田，這樣的山也頓時馴雅了。又美濃的莊宅屋舍，是美濃除了山與田之外，第三樣 最教我心動的物事。宅院為紅磚紅瓦，與遠山、水田的油綠恰成對比，亦多了幾分人煙氣，不至太過 青澀荒蔓。這便是美濃先天之至美，故我謂：美濃便只是看景。景以外，再不可更添雜項，如美濃粄 條，如美濃油紙傘，如擂茶，如藍布衫等等，方不至辜負了體會美景之原旨。」 依據上文，下列選項說明適當的是：', '["油紙傘，擂茶，藍布衫是美濃三樣最令作者心動的事物", "作者眼中美濃最美在於叢山連綿屏障、具險峻奇絕之美", "油紙傘等人文之美，增添人煙氣，使美濃不致過於荒蔓", "宅院的紅磚紅瓦，與遠山、水田對比是美濃先天之至美 作者賞看美濃的角度，是以眼穿透，看往平疇看往遠山"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00436', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「由於擔心孩子沉迷於電玩或線上遊戲，許多父母選擇禁止小孩玩遊戲，認為遊戲會導致沉迷、無法 兼顧課業的反效果，不過，Facebook 創辦人祖克柏卻抱持了不同的看法。他認為應該讓孩子們打電 動，兒童成長期間如果因為接觸遊戲而懂得如何建構、創造遊戲，這是讓他們能對程式產生興趣的方 式，也能從遊戲中學習、成長。在不沉迷、不花費零用錢玩遊戲的前提之下，適度的遊戲其實有助於 幫助頭腦發展、增強反應速度、使人更樂觀快樂等正面能量。」 關於上文意涵，下列敘述何者正確？', '["從遊戲中可以學習成長許多事，但不包括電玩或線上遊戲", "小孩應該嚴格禁止打電動，因為遊戲確實會導致沉迷，無法兼顧課業", "祖克柏的建議是偏頗、錯誤的，因為他是Facebook的創辦人，所以才會有上述主張", "適度的電玩遊戲其實有助於頭腦發展、增強反應速度、使人更樂觀，學習表現更出色 孩子成長的過程中，可以透過接觸電玩遊戲，了解如何建構遊戲，進而對程式設計產生興趣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00437', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「二十年前，在淡水河口，有一處開闊、綺麗的黃金沙岸。這塊海洋與陸地的交界，好像廣袤的沙漠。 我必須走很長很長的路，才能接近。春天時，有一群鴴鷸科水鳥熱鬧地抵達那兒，和我邂逅。牠們在 那兒打尖，覓食於潮間帶，一個多月後再北返。秋天時，那群水鳥又回來了。隊伍裡多了牠們的新一 代成員。牠們休息了一陣，繼續依循著祖先遷徙的路線南下。這種喧囂的遇見，本質其實是孤獨的。 很甜美、平淡的孤獨。我暗自喜歡。在城市裡，當一個人遇見一群人時，也有這種孤獨。但我們殘存 的這種孤獨，退化了，過於閉鎖而肥大。但在這裡，孤獨是長著翅膀，屬於開闊的。我在那兒走訪了 好幾年。我想，牠們應該認識我的。」 上文所謂「孤獨」的本質，下列形容何者正確？', '["離群索居，遠離干擾", "彼此相忘，和諧共存", "孤高傲視，唯我獨尊", "安時處順，與世無爭 寂寞空虛，百無聊賴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00438', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，本文所描寫人與鳥相遇的關係，與下列詩句的意境何者相近？', '["自去自來梁上燕，相親相近水中鷗", "蓬萊此去無多路，青鳥殷勤為探看", "晴空一鶴排雲上，便引詩情到碧霄", "仙人有待乘黃鶴，海客無心隨白鷗 今日卻回垂釣處，海鷗相見已高翔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00439', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「考乎其候也，一天澄澈，四季清和，暑無揮汗之淋漓，寒無裂膚之凜冽。入夏定霑霪雨，經秋始靉 浮雲。山氣燠而難蠶，海風飄而罕鵲。若地則無時而不動，若山則無日而不青。」 下列那些選項符合上述引文所描寫的現象？', '["氣候溫和", "世外桃源", "地震頻繁", "夏日久雨 雲霧濃密"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00440', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列選項，何者與「一日之所需，百工斯為備」意旨相近？', '["一人傅之，眾人咻之", "未雨綢繆，有備無患", "工欲善其事，必先利其器", "得之於人者太多，出之於己者太少 一粥一飯當思來處不易，半絲半縷恆念物力維艱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00441', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '古人繪畫意在筆先，景物全由心造。下列詞語能體現此種特質的是：', '["胸有丘壑", "成竹在胸", "雕繪滿眼", "智者樂水，仁者樂山 憑高視下，勢如劈竹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00442', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '我國甲市政府將其興建之跨海大橋徵收通行費之收費系統建置及營運委託乙公司辦理，兩造並簽立跨 海大橋電子收費系統建置及營運契約（下稱系爭契約）。嗣甲市政府以乙公司未依約定進度完成收費 系統，向普通法院起訴請求乙公司給付違約金。有關普通法院有無受理本件訴訟權限，下列敘述何者 錯誤？', '["普通法院認本件屬公法事件時，應依職權裁定將本件訴訟移送至行政法院", "普通法院裁定將訴訟移送至行政法院前，為保障當事人程序權，應先徵詢甲市政府及乙公司之意見", "若兩造書面合意願由普通法院為裁判，如普通法院認為系爭契約涉及公權力行使屬行政契約，仍應 將本件訴訟裁定移送至行政法院", "普通法院就有無受理本件訴訟之權限，與行政法院確定裁判見解不同時，應以裁定停止訴訟程序， 並聲請司法院解釋"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
